"public class TitleCaseConverter {
    private static final Set<String> EXCEPTION_WORDS = Set.of(\"and\", \"of\", \"the\", \"is\", \"in\", \"on\", \"at\", \"by\", \"for\", \"with\", \"as\", \"an\", \"to\", \"from\", \"about\", \"over\", \"under\", \"between\", \"into\", \"through\", \"during\", \"before\", \"after\", \"above\", \"below\", \"out\", \"up\", \"down\", \"around\", \"among\");

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        StringBuilder result = new StringBuilder();
        boolean newWord = true;

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            if (Character.isLetter(c)) {
                if (newWord) {
                    result.append(Character.toUpperCase(c));
                    newWord = false;
                } else {
                    result.append(Character.toLowerCase(c));
                }
            } else {
                result.append(c);
                newWord = true;
            }
        }

        return result.toString();
    }

    public static void main(String[] args) {
        String input = \"this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.\";

        String titleCase = toTitleCase(input);
        System.out.println(titleCase);
    }
